// BUG: tick() never advances the snake because step is 0.
export function createGame() {
  const state = { x: 0, step: 0, dir: 1 };
  function tick() {
    state.x += state.step * state.dir;
    return state.x;
  }
  return { state, tick };
}

import assert from 'node:assert/strict';
import { test } from 'node:test';
import { createGame } from './src/game.js';

test('snake advances on each tick', () => {
  const game = createGame();
  const first = game.tick();
  const second = game.tick();
  assert.ok(second > first, 'snake position should advance over ticks');
});
